class Solution:
    def max_element_on_top(self, stack: list[int]) -> int:
        if not stack:
            return -1
        max_val = stack[0]
        for i in range(len(stack) - 1, -1, -1):
            if stack[i] > max_val:
                max_val = stack[i]
        return max_val

