class Solution {
public:
    int maxElementOnTop(std::deque<int>& stack) {
        if (stack.empty()) return -1;
        int max_val = stack.front();
        while (!stack.empty())
        {
            if (stack.back() > max_val)
            {
                max_val = stack.back();
                stack.pop_back();
            }
            else
                stack.pop_back();
        }
        return max_val;
    }
};

